#include<bits/stdc++.h>
#define LL long long
#define Uint unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e7+5;
const int N2 = 1e7+5;
Uint T,up,k;
Uint cnt,p[N];
Uint q[N],q1[N],f[N2];
bool vis[N];
Uint read(){
    Uint su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
Uint QP(Uint x,Uint y){
    Uint as=1;
    while(y){
        if(y&1)as=as*x;
        x=x*x,y>>=1;
    }return as;
}
void init(){
    q[1]=1,f[1]=1;
    for(Uint i=2;i<=up;i++){
        if(!vis[i]){
            p[++cnt]=i,q[i]=QP(i,k);
            if(i<=up/2)f[i]=i-1;
        }
        for(int j=1;j<=cnt&&i*p[j]<=up;j++){
            Uint u=i*p[j];vis[u]=1;
            q[u]=q[i]*q[p[j]];
            if(i%p[j]!=0)f[u]=f[i]*f[p[j]];
            else{
                Uint v=i/p[j];
                if(v%p[j]==0)f[u]=0;
                else f[u]=-f[v]*p[j];
                break;
            }
        }
    }
    for(Uint i=1;i<=up/2;i++)
        f[i]=f[i-1]+f[i]*q[i];
    for(Uint i=1;i<=up;i++)
        q1[i]=q1[i-1]+q[i]*i,q[i]+=q[i-1];
    return;
}
Uint G(Uint x){
    Uint res=(2*x+1)*(q[x*2]-q[x]);
    res+=q1[x]-q[x]-(q1[x*2]-q1[x]);
    return res;
}
void Sol(){
    Uint n=read(),res=0;
    for(Uint l=1,r;l<=n;l=r+1){
        r=n/(n/l);
        res+=G(n/l)*(f[r]-f[l-1]);
    }cout<<res<<"\n";return;
}
int main(){
    T=read(),up=read()*2,k=read();
    init();
    while(T--)Sol();
    return 0;
}
